      "use strict";
      a.exports = JSON.parse('{"meta":{"siteName":"ToolPic","siteDescription":"Alat imej dan video dalam talian percuma. Semua pemprosesan berlaku dalam pelayar anda - fail anda tidak pernah meninggalkan peranti anda.","homeTitle":"Alat Imej & Video Dalam Talian Percuma | ToolPic"},"common":{"upload":"Muat naik fail","uploadHint":"atau seret dan lepas fail di sini","download":"Muat turun","downloadAll":"Muat turun semua","processing":"Memproses...","reset":"Tetapkan semula","privacy":"Fail anda diproses secara tempatan dalam pelayar anda. Tiada apa yang dimuat naik ke mana-mana pelayan.","maxFileSize":"Saiz fail maksimum: {size}MB","supportedFormats":"Format yang disokong: {formats}","quality":"Kualiti","width":"Lebar","height":"Tinggi","format":"Format output","start":"Mula","cancel":"Batal","done":"Selesai","error":"Ralat berlaku. Sila cuba lagi.","fileCount":"{count} fail dipilih","originalSize":"Asal: {size}","newSize":"Baharu: {size}","savedPercent":"Dijimatkan {percent}%"},"nav":{"home":"Laman Utama","imageTools":"Alat Imej","videoTools":"Alat Video","allTools":"Semua Alat","blog":"Blog"},"home":{"h1":"Alat Imej & Video Dalam Talian Percuma","subtitle":"Mampatkan, tukar dan edit fail media anda serta-merta. Tiada muat naik, tiada pendaftaran, tiada had. 100% percuma dan peribadi.","startNow":"Mula Sekarang","learnMore":"Ketahui Lagi","imageSection":"Alat Imej","imageSectionDesc":"Alat penyuntingan dan penukaran imej yang berkuasa, berjalan sepenuhnya dalam pelayar anda.","videoSection":"Alat Video","videoSectionDesc":"Lakukan operasi video biasa tanpa memuat naik fail besar. Semua pemprosesan berlaku pada peranti anda.","whyTitle":"Mengapa ToolPic?","whySubtitle":"Dibina dengan tiga prinsip teras: privasi, kebolehcapaian dan kelajuan.","why1Title":"100% Berasaskan Pelayar","why1Desc":"Semua fail diproses secara tempatan. Tiada apa yang dimuat naik ke pelayan. Privasi anda terjamin.","why2Title":"Percuma & Tanpa Had","why2Desc":"Tanpa pendaftaran, tanpa had fail, tanpa tera air. Gunakan seberapa banyak yang anda mahu, sepenuhnya percuma.","why3Title":"Pantas & Mudah","why3Desc":"Antara muka seret dan lepas yang mudah. Dapatkan keputusan dalam beberapa saat, tanpa pemasangan perisian."},"tools":{"image-compressor":{"title":"Pemampat Imej","description":"Mampatkan imej JPEG, PNG, WebP sehingga 80% tanpa kehilangan kualiti.","h1":"Mampatkan Imej Dalam Talian - Percuma & Pantas","metaTitle":"Pemampat Imej Percuma - Kurangkan Saiz Imej Dalam Talian | ToolPic","metaDescription":"Mampatkan imej JPEG, PNG, WebP, AVIF dalam talian secara percuma. Kurangkan saiz fail sehingga 80% dengan pemampatan pintar. Tanpa muat naik, 100% dalam pelayar.","howToUseTitle":"Cara Memampatkan Imej","step1Title":"Muat Naik Imej","step1Desc":"Seret dan lepas atau klik untuk memilih imej JPEG, PNG atau WebP.","step2Title":"Laraskan Kualiti","step2Desc":"Gunakan peluncur kualiti untuk mengimbangi antara saiz fail dan kualiti imej.","step3Title":"Muat Turun Keputusan","step3Desc":"Muat turun imej yang dimampatkan secara individu atau semuanya sekaligus.","featuresTitle":"Ciri-ciri Utama","feature1Title":"Pemampatan Pintar","feature1Desc":"Algoritma canggih mengurangkan saiz fail sehingga 80% sambil mengekalkan kualiti visual.","feature2Title":"Pemprosesan Berkelompok","feature2Desc":"Mampatkan berbilang imej sekaligus. Tiada had bilangan fail.","feature3Title":"100% Peribadi","feature3Desc":"Semua pemprosesan berlaku dalam pelayar anda. Imej anda tidak pernah meninggalkan peranti anda.","feature4Title":"Semua Format Disokong","feature4Desc":"Berfungsi dengan JPEG, PNG, WebP dan format imej biasa yang lain.","faqTitle":"Soalan Lazim","faq1Q":"Adakah pemampatan imej mengurangkan kualitinya?","faq1A":"Pemampatan pintar membuang data yang tidak diperlukan sambil mengekalkan kualiti visual. Pada kualiti 80%, kebanyakan imej kelihatan sama dengan asal tetapi saiznya jauh lebih kecil.","faq2Q":"Adakah had saiz fail?","faq2A":"Anda boleh memuat naik imej sehingga 50MB setiap satu. Tiada had bilangan imej yang boleh anda mampatkan.","faq3Q":"Adakah imej saya dimuat naik ke pelayan?","faq3A":"Tidak. Semua pemampatan berlaku secara tempatan dalam pelayar anda menggunakan teknologi WebAssembly. Imej anda tidak pernah meninggalkan peranti anda, menjamin privasi sepenuhnya."},"image-converter":{"title":"Penukar Imej","description":"Tukar imej antara format JPG, PNG, WebP, AVIF, BMP serta-merta.","h1":"Tukar Format Imej Dalam Talian - Percuma","metaTitle":"Penukar Imej Percuma - JPG PNG WebP AVIF Dalam Talian | ToolPic","metaDescription":"Tukar imej antara JPG, PNG, WebP, AVIF, BMP, TIFF dalam talian secara percuma. Pantas dan selamat.","howToUseTitle":"Cara Menukar Format Imej","step1Title":"Muat Naik Imej","step1Desc":"Seret dan lepas atau pilih imej JPG, PNG, WebP, AVIF atau BMP.","step2Title":"Pilih Format","step2Desc":"Pilih format sasaran yang anda ingin tukar daripada menu lungsur.","step3Title":"Muat Turun Fail Yang Ditukar","step3Desc":"Klik muat turun untuk menyimpan imej anda dalam format baharu serta-merta.","featuresTitle":"Ciri-ciri Utama","feature1Title":"Sokongan Pelbagai Format","feature1Desc":"Tukar antara JPG, PNG, WebP, AVIF, BMP dan TIFF dengan satu klik.","feature2Title":"Penukaran Berkelompok","feature2Desc":"Tukar berbilang imej sekaligus. Jimatkan masa dengan penukaran format secara pukal.","feature3Title":"Pemeliharaan Kualiti","feature3Desc":"Menukar imej sambil mengekalkan kualiti tertinggi yang mungkin dalam format sasaran.","feature4Title":"Pemprosesan Serta-merta","feature4Desc":"Penukaran berasaskan pelayar bermakna tiada menunggu muat naik atau muat turun dari pelayan.","faqTitle":"Soalan Lazim","faq1Q":"Format imej manakah yang boleh saya tukar?","faq1A":"Anda boleh menukar antara JPG, PNG, WebP, AVIF, BMP dan TIFF. Semua penukaran berlaku serta-merta dalam pelayar anda.","faq2Q":"Adakah penukaran imej mengurangkan kualitinya?","faq2A":"Penukaran ke format tanpa kehilangan seperti PNG mengekalkan kualiti penuh. Untuk format dengan kehilangan seperti JPG atau WebP, anda boleh melaraskan tetapan kualiti untuk mengawal keseimbangan antara saiz fail dan kualiti.","faq3Q":"Mengapa saya perlu menukar imej ke WebP?","faq3A":"WebP menyediakan pemampatan yang lebih baik berbanding JPG dan PNG, menghasilkan saiz fail yang lebih kecil dengan kualiti visual yang serupa. Ia disokong secara meluas oleh pelayar moden dan disyorkan untuk kegunaan web."},"image-crop":{"title":"Potong & Ubah Saiz Imej","description":"Potong dan ubah saiz imej dengan dimensi pratetap media sosial.","h1":"Potong & Ubah Saiz Imej Dalam Talian - Percuma","metaTitle":"Alat Potong & Ubah Saiz Imej Percuma Dalam Talian | ToolPic","metaDescription":"Potong dan ubah saiz imej dalam talian secara percuma. Dimensi pratetap untuk media sosial. Tanpa perlu muat naik.","howToUseTitle":"Cara Memotong & Mengubah Saiz Imej","step1Title":"Muat Naik Imej","step1Desc":"Seret dan lepas atau klik untuk memilih imej yang ingin anda potong atau ubah saiz.","step2Title":"Laraskan Kawasan Potongan","step2Desc":"Seret pemegang potongan atau pilih nisbah aspek pratetap untuk platform media sosial.","step3Title":"Muat Turun Keputusan","step3Desc":"Gunakan potongan dan muat turun imej anda yang bersaiz sempurna.","featuresTitle":"Ciri-ciri Utama","feature1Title":"Pratetap Media Sosial","feature1Desc":"Pratetap satu klik untuk Instagram, Facebook, Twitter, lakaran kecil YouTube dan banyak lagi.","feature2Title":"Nisbah Aspek Tersuai","feature2Desc":"Tetapkan sebarang lebar dan tinggi tersuai atau kunci nisbah aspek untuk pemotongan tepat.","feature3Title":"Editor Potongan Visual","feature3Desc":"Antara muka seret dan lepas yang intuitif untuk memilih kawasan yang tepat yang anda ingin simpan.","feature4Title":"Tanpa Kehilangan Kualiti","feature4Desc":"Potong dan ubah saiz tanpa pemampatan semula. Kualiti imej asal dikekalkan sepenuhnya.","faqTitle":"Soalan Lazim","faq1Q":"Apakah dimensi media sosial yang disokong?","faq1A":"Kami menyertakan pratetap untuk siaran Instagram (1080x1080), cerita Instagram (1080x1920), muka depan Facebook (820x312), pengepala Twitter (1500x500), lakaran kecil YouTube (1280x720) dan banyak lagi.","faq2Q":"Bolehkah saya mengubah saiz imej tanpa memotong?","faq2A":"Ya. Anda boleh menetapkan nilai lebar dan tinggi tersuai untuk mengubah saiz imej secara berkadar atau ke dimensi tepat tanpa memotong mana-mana bahagian.","faq3Q":"Adakah pemotongan mengurangkan kualiti imej?","faq3A":"Tidak. Pemotongan hanya membuang bahagian imej di luar kawasan yang dipilih. Bahagian yang tinggal mengekalkan kualiti asalnya."},"image-watermark":{"title":"Tambah Tera Air","description":"Tambah tera air teks atau imej pada foto anda secara berkelompok.","h1":"Tambah Tera Air pada Imej Dalam Talian - Percuma","metaTitle":"Alat Tera Air Percuma - Tambah Teks/Logo | ToolPic","metaDescription":"Tambah tera air teks atau imej pada foto dalam talian secara percuma. Pemprosesan berkelompok disokong. 100% dalam pelayar.","howToUseTitle":"Cara Menambah Tera Air","step1Title":"Muat Naik Imej","step1Desc":"Seret dan lepas atau pilih foto yang ingin anda tambah tera air.","step2Title":"Sesuaikan Tera Air","step2Desc":"Tambah teks atau muat naik logo. Laraskan kedudukan, saiz, kelegapan dan putaran.","step3Title":"Muat Turun Imej Bertera Air","step3Desc":"Gunakan tera air dan muat turun imej anda yang dilindungi.","featuresTitle":"Ciri-ciri Utama","feature1Title":"Tera Air Teks & Imej","feature1Desc":"Tambah teks tersuai dengan gaya fon atau muat naik logo anda sendiri sebagai tera air.","feature2Title":"Penyesuaian Penuh","feature2Desc":"Kawal kedudukan, saiz, kelegapan, putaran dan warna tera air anda dengan tepat.","feature3Title":"Tera Air Berkelompok","feature3Desc":"Gunakan tera air yang sama pada berbilang imej sekaligus. Sesuai untuk jurugambar.","feature4Title":"Lindungi Karya Anda","feature4Desc":"Cegah penggunaan foto anda tanpa kebenaran dengan menambah tanda pemilikan yang kelihatan.","faqTitle":"Soalan Lazim","faq1Q":"Bolehkah saya menggunakan logo saya sendiri sebagai tera air?","faq1A":"Ya. Anda boleh memuat naik sebarang imej PNG atau JPG sebagai tera air. Imej PNG dengan latar belakang lutsinar berfungsi paling baik untuk tera air logo.","faq2Q":"Bolehkah saya menambah tera air pada berbilang imej sekaligus?","faq2A":"Ya. Muat naik berbilang imej dan tetapan tera air yang sama akan digunakan pada kesemuanya. Anda boleh memuat turun semua imej bertera air sekaligus.","faq3Q":"Adakah tera air menjejaskan kualiti imej?","faq3A":"Tera air digunakan sebagai lapisan tanpa memampatkan semula imej asas. Kualiti imej asal anda dikekalkan."},"image-bg-remove":{"title":"Buang Latar Belakang","description":"Pembuangan latar belakang berkuasa AI. Dapatkan PNG lutsinar dalam beberapa saat.","h1":"Buang Latar Belakang Imej Dalam Talian - Alat AI Percuma","metaTitle":"Pembuang Latar Belakang Percuma - AI Buang BG Dalam Talian | ToolPic","metaDescription":"Buang latar belakang imej dengan AI dalam talian secara percuma. PNG lutsinar dalam beberapa saat. Tanpa muat naik, 100% peribadi.","howToUseTitle":"Cara Membuang Latar Belakang Imej","step1Title":"Muat Naik Imej","step1Desc":"Seret dan lepas atau pilih imej yang ingin anda buang latar belakangnya.","step2Title":"Pemprosesan AI","step2Desc":"Model AI kami secara automatik mengesan subjek dan membuang latar belakang.","step3Title":"Muat Turun PNG Lutsinar","step3Desc":"Muat turun imej anda dengan latar belakang lutsinar sebagai fail PNG.","featuresTitle":"Ciri-ciri Utama","feature1Title":"Pengesanan Berkuasa AI","feature1Desc":"Model pembelajaran mesin canggih memisahkan subjek latar depan daripada latar belakang dengan tepat.","feature2Title":"Keputusan Serta-merta","feature2Desc":"Dapatkan PNG lutsinar dalam beberapa saat. Tiada penyuntingan manual atau alat pemilihan diperlukan.","feature3Title":"Berfungsi Dengan Sebarang Subjek","feature3Desc":"Manusia, produk, haiwan, objek \u2014 AI mengendalikan semua jenis subjek dengan tepat.","feature4Title":"Berjalan Dalam Pelayar Anda","feature4Desc":"Model AI berjalan sepenuhnya dalam pelayar anda menggunakan WebAssembly. Imej anda kekal peribadi.","faqTitle":"Soalan Lazim","faq1Q":"Bagaimana pembuangan latar belakang AI berfungsi?","faq1A":"Kami menggunakan model rangkaian neural yang berjalan terus dalam pelayar anda. Ia menganalisis imej untuk mengenal pasti subjek utama dan mencipta topeng yang tepat untuk membuang latar belakang.","faq2Q":"Jenis imej apakah yang berfungsi paling baik?","faq2A":"AI berfungsi paling baik dengan subjek yang jelas yang mempunyai kontras yang baik dengan latar belakang. Foto manusia, produk dan haiwan biasanya menghasilkan keputusan yang sangat baik.","faq3Q":"Adakah imej saya dihantar ke pelayan untuk pemprosesan?","faq3A":"Tidak. Model AI dimuatkan ke dalam pelayar anda dan semua pemprosesan berlaku secara tempatan pada peranti anda. Imej anda tidak pernah dimuat naik ke mana-mana pelayan."},"image-merge":{"title":"Gabung Imej","description":"Gabungkan beberapa imej menjadi satu. Cipta kolaj dan imej panjang.","h1":"Gabung Imej Dalam Talian - Pembuat Kolaj Percuma","metaTitle":"Alat Gabung Imej Percuma Dalam Talian | ToolPic","metaDescription":"Gabungkan beberapa imej menjadi satu dalam talian secara percuma. Cipta kolaj, imej panjang. Tanpa perlu muat naik.","howToUseTitle":"Cara Menggabungkan Imej","step1Title":"Muat Naik Imej","step1Desc":"Seret dan lepas atau pilih dua atau lebih imej yang ingin anda gabungkan.","step2Title":"Susun Susun Atur","step2Desc":"Pilih susun atur mendatar, menegak atau grid. Laraskan jarak dan penjajaran.","step3Title":"Muat Turun Imej Yang Digabungkan","step3Desc":"Eksport imej gabungan anda sebagai satu fail dalam format pilihan anda.","featuresTitle":"Ciri-ciri Utama","feature1Title":"Susun Atur Fleksibel","feature1Desc":"Gabungkan imej secara mendatar, menegak atau dalam grid. Cipta imej panjang atau kolaj foto.","feature2Title":"Jarak Tersuai","feature2Desc":"Tambah padding dan jurang antara imej. Pilih warna latar belakang untuk kawasan jarak.","feature3Title":"Seret Untuk Menyusun Semula","feature3Desc":"Susun semula susunan imej dengan mudah dengan menyeret dan melepaskan lakaran kecil.","feature4Title":"Tanpa Had Imej","feature4Desc":"Gabungkan seberapa banyak imej yang anda perlukan. Tiada sekatan pada bilangan foto.","faqTitle":"Soalan Lazim","faq1Q":"Berapa banyak imej yang boleh saya gabungkan sekaligus?","faq1A":"Tiada had tetap pada bilangan imej. Anda boleh menggabungkan seberapa banyak yang pelayar anda boleh kendalikan. Untuk prestasi terbaik, kami syorkan menggabungkan sehingga 20 imej pada satu masa.","faq2Q":"Bolehkah saya menggabungkan imej dengan saiz yang berbeza?","faq2A":"Ya. Alat ini secara automatik melaraskan imej supaya sesuai bersama. Anda boleh memilih untuk memadankan lebar, tinggi atau mengekalkan perkadaran asal.","faq3Q":"Apakah format output imej yang digabungkan?","faq3A":"Imej yang digabungkan disimpan sebagai PNG secara lalai untuk mengekalkan kualiti. Anda juga boleh memilih JPG atau WebP untuk saiz fail yang lebih kecil."},"video-compress":{"title":"Pemampat Video","description":"Mampatkan fail video dengan melaraskan resolusi dan kadar bit.","h1":"Mampatkan Video Dalam Talian - Percuma & Pantas","metaTitle":"Pemampat Video Percuma - Kurangkan Saiz Video Dalam Talian | ToolPic","metaDescription":"Mampatkan video MP4, WebM, AVI dalam talian secara percuma. Kurangkan saiz fail tanpa kehilangan kualiti. Berasaskan pelayar.","howToUseTitle":"Cara Memampatkan Video","step1Title":"Muat Naik Video","step1Desc":"Seret dan lepas atau pilih fail video MP4, WebM, AVI atau MOV.","step2Title":"Pilih Tetapan","step2Desc":"Laraskan resolusi, kadar bit dan tetapan kualiti untuk mengawal saiz fail output.","step3Title":"Muat Turun Video Yang Dimampatkan","step3Desc":"Tunggu pemprosesan selesai, kemudian muat turun fail video anda yang lebih kecil.","featuresTitle":"Ciri-ciri Utama","feature1Title":"Pengurangan Saiz Ketara","feature1Desc":"Kurangkan saiz fail video sehingga 70% sambil mengekalkan kualiti tontonan.","feature2Title":"Kawalan Resolusi","feature2Desc":"Kurangkan resolusi video dari 4K kepada 1080p, 720p atau 480p untuk fail yang lebih kecil.","feature3Title":"Pemprosesan Berasaskan Pelayar","feature3Desc":"Video dimampatkan secara tempatan menggunakan FFmpeg WebAssembly. Tiada muat naik pelayan diperlukan.","feature4Title":"Sokongan Pelbagai Format","feature4Desc":"Mampatkan fail video MP4, WebM, AVI, MOV dan MKV.","faqTitle":"Soalan Lazim","faq1Q":"Berapa lama masa yang diperlukan untuk pemampatan video?","faq1A":"Masa pemprosesan bergantung pada panjang video, resolusi dan prestasi peranti anda. Video 1080p selama 1 minit biasanya mengambil masa 30-60 saat untuk dimampatkan.","faq2Q":"Apakah saiz fail video maksimum?","faq2A":"Memandangkan pemprosesan berlaku dalam pelayar anda, had bergantung pada memori peranti anda yang tersedia. Kebanyakan peranti boleh mengendalikan video sehingga 500MB-1GB dengan selesa.","faq3Q":"Adakah pemampatan akan menjadikan video saya kelihatan buruk?","faq3A":"Dengan tetapan lalai, perbezaan kualiti visual adalah minimum. Anda boleh melaraskan peluncur kualiti untuk mencari keseimbangan sempurna antara saiz fail dan kualiti visual."},"video-convert":{"title":"Penukar Video","description":"Tukar video antara format MP4, WebM, AVI, MOV.","h1":"Tukar Format Video Dalam Talian - Percuma","metaTitle":"Penukar Video Percuma - MP4 WebM AVI MOV Dalam Talian | ToolPic","metaDescription":"Tukar video antara MP4, WebM, AVI, MOV, MKV dalam talian secara percuma. Penukaran pantas dalam pelayar.","howToUseTitle":"Cara Menukar Format Video","step1Title":"Muat Naik Video","step1Desc":"Seret dan lepas atau pilih fail video yang ingin anda tukar.","step2Title":"Pilih Format Output","step2Desc":"Pilih format sasaran anda: MP4, WebM, AVI, MOV atau MKV.","step3Title":"Muat Turun Video Yang Ditukar","step3Desc":"Tunggu penukaran selesai, kemudian muat turun video anda dalam format baharu.","featuresTitle":"Ciri-ciri Utama","feature1Title":"Sokongan Format Meluas","feature1Desc":"Tukar antara MP4, WebM, AVI, MOV dan MKV untuk sebarang peranti atau platform.","feature2Title":"Tetapan Kualiti","feature2Desc":"Laraskan kualiti video dan tetapan codec untuk mengoptimumkan saiz atau kualiti.","feature3Title":"Tanpa Perisian Diperlukan","feature3Desc":"Tukar video terus dalam pelayar anda tanpa memasang sebarang perisian.","feature4Title":"Peribadi & Selamat","feature4Desc":"Fail video anda tidak pernah meninggalkan peranti anda. Semua penukaran berlaku secara tempatan menggunakan WebAssembly.","faqTitle":"Soalan Lazim","faq1Q":"Format video manakah yang patut saya pilih?","faq1A":"MP4 (H.264) adalah format yang paling serasi secara meluas dan berfungsi pada hampir semua peranti dan platform. WebM sesuai untuk kegunaan web dengan saiz fail yang lebih kecil. MOV diutamakan untuk peranti Apple.","faq2Q":"Bolehkah saya menukar fail video yang besar?","faq2A":"Ya, tetapi memandangkan penukaran berlaku dalam pelayar anda, prestasi bergantung pada peranti anda. Kebanyakan peranti mengendalikan fail sehingga 500MB-1GB dengan lancar. Untuk fail yang lebih besar, pelayar desktop disyorkan.","faq3Q":"Adakah penukaran menjejaskan kualiti video?","faq3A":"Anda boleh memilih kualiti output semasa penukaran. Dengan tetapan kualiti tinggi, perbezaan daripada asal boleh diabaikan. Tetapan kualiti yang lebih rendah menghasilkan fail yang lebih kecil."},"video-to-gif":{"title":"Video ke GIF","description":"Tukar klip video kepada GIF animasi dengan tetapan tersuai.","h1":"Tukar Video ke GIF Dalam Talian - Percuma","metaTitle":"Penukar Video ke GIF Percuma Dalam Talian | ToolPic","metaDescription":"Tukar video ke GIF dalam talian secara percuma. Sesuaikan kadar bingkai, saiz dan tempoh. Tanpa perisian.","howToUseTitle":"Cara Menukar Video ke GIF","step1Title":"Muat Naik Video","step1Desc":"Seret dan lepas atau pilih fail video MP4, WebM atau lain-lain.","step2Title":"Sesuaikan Tetapan GIF","step2Desc":"Tetapkan masa mula, tempoh, kadar bingkai dan saiz output untuk GIF anda.","step3Title":"Muat Turun GIF","step3Desc":"Jana dan muat turun fail GIF animasi anda.","featuresTitle":"Ciri-ciri Utama","feature1Title":"Potong & Pilih","feature1Desc":"Pilih titik mula yang tepat dan tempoh segmen video untuk ditukar menjadi GIF.","feature2Title":"Kawalan Kadar Bingkai","feature2Desc":"Laraskan FPS untuk mengimbangi antara animasi lancar dan saiz fail yang lebih kecil.","feature3Title":"Ubah Saiz Output","feature3Desc":"Tetapkan lebar tersuai untuk GIF anda. Dimensi yang lebih kecil menghasilkan saiz fail yang jauh lebih kecil.","feature4Title":"Pratonton Sebelum Muat Turun","feature4Desc":"Lihat pratonton GIF anda sebelum memuat turun untuk memastikan ia kelihatan tepat seperti yang dikehendaki.","faqTitle":"Soalan Lazim","faq1Q":"Bagaimana saya boleh menjadikan fail GIF saya lebih kecil?","faq1A":"Kurangkan lebar output, turunkan kadar bingkai (10-12 FPS biasanya mencukupi) dan pastikan tempohnya pendek. Tiga faktor ini mempunyai kesan terbesar pada saiz fail GIF.","faq2Q":"Apakah kadar bingkai yang patut saya gunakan?","faq2A":"Untuk kebanyakan GIF, 10-15 FPS menyediakan animasi lancar dengan saiz fail yang munasabah. Kadar bingkai yang lebih tinggi mencipta gerakan yang lebih lancar tetapi fail yang jauh lebih besar.","faq3Q":"Adakah had masa untuk video?","faq3A":"Tiada had masa yang ketat, tetapi GIF paling sesuai untuk klip pendek (di bawah 10 saat). GIF yang lebih panjang menghasilkan saiz fail yang sangat besar yang mungkin tidak praktikal untuk dikongsi."},"video-extract-audio":{"title":"Ekstrak Audio","description":"Ekstrak trek audio daripada fail video sebagai MP3, WAV atau AAC.","h1":"Ekstrak Audio daripada Video Dalam Talian - Percuma","metaTitle":"Pengekstrak Audio Percuma - Dapatkan MP3 daripada Video | ToolPic","metaDescription":"Ekstrak audio daripada video dalam talian secara percuma. Simpan sebagai MP3, WAV atau AAC. Pengekstrakan pantas dalam pelayar.","howToUseTitle":"Cara Mengekstrak Audio daripada Video","step1Title":"Muat Naik Video","step1Desc":"Seret dan lepas atau pilih fail video yang mengandungi audio yang ingin anda ekstrak.","step2Title":"Pilih Format Audio","step2Desc":"Pilih format output pilihan anda: MP3, WAV atau AAC.","step3Title":"Muat Turun Fail Audio","step3Desc":"Tunggu pengekstrakan selesai, kemudian muat turun fail audio.","featuresTitle":"Ciri-ciri Utama","feature1Title":"Pelbagai Format Audio","feature1Desc":"Eksport audio sebagai MP3 untuk keserasian universal, WAV untuk kualiti tanpa kehilangan atau AAC untuk pemampatan yang cekap.","feature2Title":"Pengekstrakan Pantas","feature2Desc":"Pengekstrakan audio lebih pantas daripada penukaran video penuh kerana hanya strim audio yang diproses.","feature3Title":"Semua Format Video","feature3Desc":"Ekstrak audio daripada MP4, WebM, AVI, MOV, MKV dan format video biasa yang lain.","feature4Title":"Output Kualiti Tinggi","feature4Desc":"Ekstrak trek audio asal tanpa pengekodan semula untuk kualiti terbaik yang mungkin.","faqTitle":"Soalan Lazim","faq1Q":"Format audio manakah yang patut saya pilih?","faq1A":"MP3 adalah format yang paling serasi secara meluas dan berfungsi di mana-mana. WAV menyediakan kualiti tanpa kehilangan yang tidak dimampatkan tetapi mencipta fail yang lebih besar. AAC menawarkan kualiti yang lebih baik daripada MP3 pada saiz fail yang serupa.","faq2Q":"Bolehkah saya mengekstrak audio daripada video YouTube?","faq2A":"Alat ini berfungsi dengan fail video pada peranti anda. Anda perlu memuat turun fail video terlebih dahulu, kemudian muat naik di sini untuk mengekstrak trek audio.","faq3Q":"Adakah kualiti audio akan sama seperti asal?","faq3A":"Apabila mengekstrak ke format tanpa kehilangan seperti WAV, kualiti audio sepadan dengan asal. Apabila mengekstrak ke MP3 atau AAC, pemampatan ringan digunakan tetapi kualiti kekal cemerlang pada tetapan kadar bit yang tinggi."}},"seoPages":{"privacy":"Your files are processed locally in your browser. Nothing is uploaded to any server.","convertJpgToPng":"Convert JPG to PNG Online - Free","convertJpgToPngDesc":"Convert JPG/JPEG images to PNG format online for free. Preserve transparency and quality. No upload needed, 100% browser-based.","convertJpgToWebp":"Convert JPG to WebP Online - Free","convertJpgToWebpDesc":"Convert JPG images to WebP format for smaller file sizes with the same quality. Perfect for web optimization.","convertPngToJpg":"Convert PNG to JPG Online - Free","convertPngToJpgDesc":"Convert PNG images to JPG format online for free. Reduce file size while maintaining visual quality. No software needed.","convertPngToWebp":"Convert PNG to WebP Online - Free","convertPngToWebpDesc":"Convert PNG images to WebP format for significantly smaller file sizes. Ideal for faster website loading.","convertWebpToJpg":"Convert WebP to JPG Online - Free","convertWebpToJpgDesc":"Convert WebP images to JPG format online for free. Make your images compatible with all devices and software.","convertWebpToPng":"Convert WebP to PNG Online - Free","convertWebpToPngDesc":"Convert WebP images to PNG format online for free. Get lossless quality with full transparency support.","convertHeicToJpg":"Convert HEIC to JPG Online - Free","convertHeicToJpgDesc":"Convert iPhone HEIC/HEIF photos to JPG format online for free. Make your Apple photos universally compatible.","convertBmpToJpg":"Convert BMP to JPG Online - Free","convertBmpToJpgDesc":"Convert BMP bitmap images to JPG format online for free. Dramatically reduce file size from uncompressed BMP files.","convertMp4ToWebm":"Convert MP4 to WebM Online - Free","convertMp4ToWebmDesc":"Convert MP4 videos to WebM format online for free. WebM offers smaller file sizes ideal for web embedding.","convertMp4ToAvi":"Convert MP4 to AVI Online - Free","convertMp4ToAviDesc":"Convert MP4 videos to AVI format online for free. AVI provides wide compatibility with older media players and editors.","convertWebmToMp4":"Convert WebM to MP4 Online - Free","convertWebmToMp4Desc":"Convert WebM videos to MP4 format online for free. MP4 is the most universally compatible video format.","convertMp4ToGif":"Convert MP4 to GIF Online - Free","convertMp4ToGifDesc":"Convert MP4 video clips to animated GIF online for free. Create shareable GIFs from any video. Custom frame rate and size.","compressJpg":"Compress JPG Images Online - Free","compressJpgDesc":"Compress JPG/JPEG images online for free. Reduce file size up to 80% without visible quality loss. No upload required.","compressPng":"Compress PNG Images Online - Free","compressPngDesc":"Compress PNG images online for free. Reduce PNG file size while preserving transparency and quality. 100% browser-based.","compressWebp":"Compress WebP Images Online - Free","compressWebpDesc":"Compress WebP images online for free. Optimize WebP file size for faster web performance without sacrificing quality.","compressMp4":"Compress MP4 Videos Online - Free","compressMp4Desc":"Compress MP4 video files online for free. Reduce video size by up to 70% while maintaining watchable quality. No server upload.","resizeInstagram":"Resize Image for Instagram - Free Online Tool","resizeInstagramDesc":"Resize and crop images to perfect Instagram dimensions online for free. Supports posts (1080x1080), stories (1080x1920), and reels.","resizeFacebook":"Resize Image for Facebook - Free Online Tool","resizeFacebookDesc":"Resize images for Facebook cover photos, profile pictures, and posts online for free. Get the perfect dimensions every time.","resizeTwitter":"Resize Image for Twitter/X - Free Online Tool","resizeTwitterDesc":"Resize images for Twitter/X headers (1500x500), posts, and profile pictures online for free. Optimized for the platform.","resizeYoutube":"Resize Image for YouTube Thumbnail - Free","resizeYoutubeDesc":"Create perfect YouTube thumbnails at 1280x720 pixels online for free. Crop and resize images to the ideal thumbnail size.","removeBg":"Remove Image Background Online - Free AI Tool","removeBgDesc":"Remove backgrounds from images online for free using AI. Get transparent PNG in seconds. Works with people, products, and objects.","addWatermark":"Add Watermark to Photos Online - Free","addWatermarkDesc":"Add text or logo watermarks to your photos online for free. Protect your images with custom watermarks. Batch processing supported.","mergePhotos":"Merge Photos Online - Free Image Combiner","mergePhotosDesc":"Combine and merge multiple photos into one image online for free. Create collages, side-by-side comparisons, and long images.","extractMp3":"Extract MP3 from Video Online - Free","extractMp3Desc":"Extract audio from video files and save as MP3 online for free. Works with MP4, WebM, AVI, and other video formats."},"footer":{"tagline":"Alat dalam talian percuma untuk imej dan video. 100% dalam pelayar, fail anda tidak pernah meninggalkan peranti anda.","tools":"Alat","legal":"Undang-undang","privacy":"Dasar Privasi","terms":"Terma Perkhidmatan","contact":"Hubungi","copyright":"\xA9 2026 ToolPic. Hak cipta terpelihara."},"blog":{"title":"Blog","subtitle":"Tips, panduan, dan tutorial untuk pemprosesan imej dan video","readTime":"{minutes} minit bacaan","relatedTools":"Alat Berkaitan","posts":{"how-to-compress-images-without-losing-quality":{"title":"Cara Memampatkan Imej Tanpa Kehilangan Kualiti","metaTitle":"Cara Memampatkan Imej Tanpa Kehilangan Kualiti | Blog ToolPic","metaDescription":"Pelajari teknik terbaik untuk mengurangkan saiz fail imej sambil mengekalkan kualiti visual. Panduan praktikal dengan tips untuk pemampatan JPEG, PNG dan WebP.","excerpt":"Pelajari teknik terbaik untuk mengurangkan saiz fail imej sambil mengekalkan kualiti visual untuk web dan mudah alih.","content":[{"heading":"Mengapa Pemampatan Imej Penting","text":"Imej bersaiz besar adalah salah satu sebab utama laman web lambat dimuat. Apabila halaman mengambil masa lebih tiga saat untuk dimuat, lebih separuh pelawat akan meninggalkan sebelum melihat kandungan anda. Enjin carian juga mengambil kira kelajuan halaman dalam algoritma kedudukan mereka, jadi imej berat boleh menjejaskan kedudukan carian anda secara langsung.\\n\\nSelain prestasi laman web, imej yang dimampatkan lebih mudah dikongsi melalui e-mel, aplikasi pesanan, dan platform media sosial yang mempunyai had saiz fail. Foto 5MB dari telefon mungkin kelihatan hebat tetapi jauh lebih besar daripada yang diperlukan untuk kegunaan dalam talian. Mengurangkannya kepada 500KB atau kurang boleh menjadikannya dimuat sepuluh kali lebih pantas tanpa penurunan kualiti yang ketara.\\n\\nPemampatan imej amat penting untuk kedai e-dagang, portfolio, dan blog berisi kandungan di mana berpuluh-puluh imej muncul di satu halaman."},{"heading":"Pemampatan Lossy vs Lossless","text":"Terdapat dua pendekatan asas untuk pemampatan imej: lossy dan lossless. Memahami perbezaannya membantu anda memilih kaedah yang tepat.\\n\\nPemampatan lossless mengurangkan saiz fail dengan mencari dan menghapuskan corak data berlebihan tanpa membuang maklumat imej. PNG menggunakan pemampatan lossless, sesuai untuk grafik, logo dan tangkapan skrin. Kelemahannya ialah biasanya hanya mencapai pengurangan sederhana, antara 10% dan 40%.\\n\\nPemampatan lossy mencapai pengurangan saiz yang jauh lebih besar dengan membuang data imej yang mata manusia tidak mungkin perasan. JPEG adalah format lossy paling biasa, dan format moden seperti WebP menawarkan pemampatan lossy yang lebih baik. Pada tetapan kualiti 75% hingga 85%, kebanyakan foto secara visual tidak dapat dibezakan daripada asal sambil 60% hingga 80% lebih kecil."},{"heading":"Amalan Terbaik untuk Pemampatan Imej","text":"Mulakan dengan memilih format yang tepat. Gunakan JPEG atau WebP untuk foto dan imej kompleks dengan kecerunan. Gunakan PNG untuk grafik dengan tepi tajam, tindanan teks, atau ketelusan. Elakkan menggunakan PNG untuk foto kerana ia menghasilkan fail yang besar tanpa perlu.\\n\\nUbah saiz imej kepada dimensi sebenar yang akan dipaparkan sebelum memampatkan. Tidak ada gunanya menyajikan imej lebar 4000 piksel untuk bekas yang hanya lebar 800 piksel.\\n\\nUntuk kegunaan web, sasarkan saiz fail di bawah 200KB untuk imej utama dan di bawah 100KB untuk lakaran kecil. Gunakan tetapan kualiti 75% hingga 85% untuk JPEG dan WebP."},{"heading":"Cara Memampatkan Imej dengan ToolPic","text":"Langkah 1: Buka alat Pemampat Imej di ToolPic. Anda boleh menyeret dan melepas imej ke kawasan muat naik, atau klik untuk memilih fail. Beberapa imej boleh diproses sekaligus.\\n\\nLangkah 2: Laraskan peluncur kualiti untuk menetapkan tahap pemampatan yang dikehendaki. Tetapan lalai 80% berfungsi baik untuk kebanyakan foto. Alat menunjukkan anggaran pengurangan saiz fail secara masa nyata.\\n\\nLangkah 3: Selepas pemprosesan selesai, semak perbandingan sebelum dan selepas. Muat turun imej secara individu atau gunakan butang \\"Muat Turun Semua\\". Fail anda tidak pernah meninggalkan pelayar \u2014 seluruh proses sepenuhnya peribadi."}],"relatedToolIds":"image-compressor"},"jpg-vs-png-vs-webp-which-image-format":{"title":"JPG vs PNG vs WebP: Format Imej Mana Yang Patut Digunakan?","metaTitle":"JPG vs PNG vs WebP: Format Imej Mana Yang Patut Digunakan? | Blog ToolPic","metaDescription":"Bandingkan format imej JPG, PNG, dan WebP. Ketahui bila menggunakan setiap format berdasarkan kualiti, saiz fail, ketelusan, dan sokongan pelayar.","excerpt":"Perbandingan praktikal format JPG, PNG, dan WebP untuk membantu anda memilih yang tepat untuk setiap situasi.","content":[{"heading":"Memahami Format Imej","text":"Memilih format imej yang tepat boleh memberi perbezaan besar dalam saiz fail, kelajuan pemuatan, dan kualiti visual. Setiap format direka untuk kegunaan yang berbeza.\\n\\nTiga format terpenting untuk web hari ini ialah JPEG (JPG), PNG, dan WebP. JPEG telah menjadi standard untuk foto sejak pertengahan 1990-an. PNG menjadi format pilihan untuk grafik dan imej yang memerlukan ketelusan. WebP, dibangunkan oleh Google, adalah format moden yang bertujuan menggantikan kedua-duanya.\\n\\nMemahami kekuatan dan batasan setiap format adalah penting untuk sesiapa yang bekerja dengan imej."},{"heading":"JPEG: Standard Fotografi","text":"JPEG menggunakan pemampatan lossy yang cemerlang dalam mewakilkan foto dan imej dengan peralihan warna yang lancar. Ia boleh mengurangkan saiz fail foto sebanyak 80% atau lebih sambil mengekalkan kualiti visual yang sangat baik.\\n\\nKelebihan utama JPEG adalah keserasian universal. Setiap peranti, pelayar, dan aplikasi menyokongnya.\\n\\nNamun, JPEG mempunyai batasan. Ia tidak menyokong ketelusan. Ia juga memperkenalkan artifak pada tetapan kualiti rendah. Setiap kali anda mengedit dan menyimpan semula JPEG, kualiti merosot lagi."},{"heading":"PNG: Kualiti Lossless dan Ketelusan","text":"PNG menggunakan pemampatan lossless \u2014 kualiti imej dikekalkan sempurna tidak kira berapa kali anda simpan. Ia juga menyokong ketelusan alfa penuh.\\n\\nIni menjadikan PNG pilihan terbaik untuk logo, ikon, tangkapan skrin, dan grafik dengan teks. Juga sesuai untuk imej yang akan diedit berulang kali.\\n\\nPertukaran adalah saiz fail. Fail PNG biasanya tiga hingga lima kali lebih besar daripada JPEG untuk kandungan fotografi. Gunakan PNG apabila kualiti dan ketelusan lebih penting daripada saiz."},{"heading":"WebP: Pilihan Moden","text":"WebP dibangunkan oleh Google untuk menyediakan pemampatan unggul untuk imej web. Ia menyokong pemampatan lossy dan lossless, serta ketelusan dan animasi \u2014 menggabungkan ciri terbaik JPEG, PNG, dan GIF.\\n\\nDalam amalan, imej WebP lossy biasanya 25% hingga 35% lebih kecil daripada JPEG pada kualiti visual setara. WebP lossless kira-kira 26% lebih kecil daripada PNG.\\n\\nSokongan pelayar untuk WebP kini cemerlang, meliputi Chrome, Firefox, Safari, dan Edge. Untuk penerbitan web di mana prestasi penting, WebP adalah pemenang jelas. Anda boleh menggunakan Penukar Imej ToolPic untuk bertukar antara format dengan mudah."}],"relatedToolIds":"image-converter"},"how-to-convert-video-to-gif":{"title":"Cara Menukar Video ke GIF: Panduan Lengkap","metaTitle":"Cara Menukar Video ke GIF: Panduan Lengkap | Blog ToolPic","metaDescription":"Pelajari cara menukar klip video ke format GIF dengan tetapan optimum. Tips untuk kadar bingkai, resolusi, dan saiz fail.","excerpt":"Semua yang anda perlu tahu tentang menukar klip video kepada GIF berkualiti tinggi dengan saiz fail yang munasabah.","content":[{"heading":"Mengapa GIF Kekal Popular","text":"Walaupun format dari 1987, GIF lebih popular berbanding sebelum ini. Ia dimainkan secara automatik dalam hampir setiap aplikasi pesanan, platform media sosial, dan klien e-mel tanpa memerlukan pemain video. Sesuai untuk reaksi, demonstrasi, dan tutorial ringkas.\\n\\nGIF juga digunakan secara meluas untuk demo produk, animasi UI, dan laporan pepijat dalam konteks profesional.\\n\\nBatasan utama ialah saiz fail. GIF menggunakan kaedah pemampatan yang agak tidak cekap dan terhad kepada 256 warna setiap bingkai."},{"heading":"Memilih Tetapan Yang Tepat","text":"Tiga tetapan terpenting semasa menukar video ke GIF ialah tempoh, kadar bingkai, dan dimensi output. Kekalkan GIF pendek \u2014 di bawah 5 saat adalah ideal.\\n\\nKadar bingkai mempunyai kesan besar pada saiz fail. Video biasanya berjalan pada 24-30 bingkai sesaat, tetapi GIF kelihatan lancar pada hanya 10-15 FPS. Menurunkan dari 30 FPS kepada 12 FPS mengurangkan saiz fail lebih separuh."},{"heading":"Mengoptimumkan Saiz Fail GIF","text":"Resolusi adalah faktor terbesar. Untuk kebanyakan kegunaan, lebar 480 hingga 640 piksel sudah mencukupi.\\n\\nPengurangan warna juga membantu. GIF menyokong maksimum 256 warna setiap bingkai.\\n\\nPertimbangkan sama ada anda benar-benar memerlukan GIF. Alternatif moden seperti animasi WebP dan gelung MP4 pendek menghasilkan fail yang jauh lebih kecil dengan kualiti lebih baik."},{"heading":"Mencipta GIF dengan ToolPic","text":"Buka alat Video ke GIF di ToolPic dan muat naik fail video. Alat menyokong MP4, WebM, dan format biasa lain. Gunakan peluncur garis masa untuk memilih titik mula dan tempoh.\\n\\nTetapkan lebar output \u2014 480px untuk media sosial. Laraskan kadar bingkai kepada 10-12 FPS. Alat menunjukkan anggaran saiz fail.\\n\\nKlik tukar dan muat turun GIF yang dioptimumkan. Seluruh proses berlaku dalam pelayar \u2014 fail video anda kekal peribadi."}],"relatedToolIds":"video-to-gif"},"best-image-compression-tools-2026":{"title":"5 Alat Pemampatan Imej Percuma Terbaik pada 2026","metaTitle":"5 Alat Pemampatan Imej Percuma Terbaik pada 2026 | Blog ToolPic","metaDescription":"Bandingkan alat pemampatan imej percuma terbaik pada 2026. Pilihan berasaskan pelayar vs desktop, ciri privasi, dan kualiti pemampatan.","excerpt":"Perbandingan jujur alat pemampatan imej percuma terbaik pada 2026, termasuk pilihan berasaskan pelayar dan desktop.","content":[{"heading":"Apa Yang Menjadikan Alat Pemampatan Bagus","text":"Alat pemampatan imej yang bagus perlu mengimbangi tiga perkara: nisbah pemampatan, kualiti visual, dan kemudahan penggunaan.\\n\\nPrivasi juga semakin penting. Alat yang memproses imej di pelayan mereka memerlukan anda memuat naik fail. Untuk imej sensitif, alat berasaskan pelayar yang memproses semuanya secara tempatan mempunyai kelebihan yang jelas.\\n\\nFaktor lain termasuk sokongan pemprosesan berkelompok, pilihan format, dan had saiz fail."},{"heading":"Alat Berasaskan Pelayar","text":"ToolPic memproses imej sepenuhnya dalam pelayar menggunakan teknologi WebAssembly. Fail anda tidak pernah meninggalkan peranti. Menyokong JPEG, PNG, WebP, dan AVIF dengan tetapan kualiti boleh laras dan pemprosesan berkelompok. Tiada had atau tera air.\\n\\nSquoosh dari pasukan Google Chrome cemerlang untuk imej tunggal tetapi hanya memproses satu imej pada satu masa.\\n\\nTinyPNG popular tetapi versi percuma terhad kepada 20 imej dan 5MB, dan imej dimuat naik ke pelayan mereka."},{"heading":"Alat Desktop dan CLI","text":"ImageOptim adalah aplikasi desktop percuma untuk macOS. Sangat baik untuk fail PNG dan boleh memproses seluruh folder.\\n\\nSharpJS adalah pustaka pemprosesan imej Node.js berprestasi tinggi untuk pembangun.\\n\\nUntuk kebanyakan pengguna, alat berasaskan pelayar menawarkan gabungan terbaik kemudahan dan kualiti."},{"heading":"Perbandingan Privasi","text":"Alat berasaskan pelayan seperti TinyPNG memuat naik imej ke pelayan jauh.\\n\\nAlat berasaskan pelayar seperti ToolPic dan Squoosh tidak pernah memuat naik fail anda. Semua pemprosesan berlaku secara tempatan. Pilihan jelas untuk imej sulit, kerja klien, dan foto peribadi.\\n\\nUntuk jurugambar profesional dan perniagaan e-dagang, pemprosesan dalam pelayar menghapuskan risiko pendedahan data sepenuhnya."}],"relatedToolIds":"image-compressor"},"how-to-remove-image-background-free":{"title":"Cara Membuang Latar Belakang Imej Secara Percuma Dalam Talian","metaTitle":"Cara Membuang Latar Belakang Imej Secara Percuma Dalam Talian | Blog ToolPic","metaDescription":"Pelajari cara membuang latar belakang imej secara percuma menggunakan alat AI dalam talian. Tips untuk e-dagang, media sosial, dan kegunaan profesional.","excerpt":"Buang latar belakang imej serta-merta dengan alat AI percuma. Sesuai untuk foto produk, media sosial, dan kandungan profesional.","content":[{"heading":"Bagaimana Pembuangan Latar Belakang AI Berfungsi","text":"Alat pembuangan latar belakang moden menggunakan model pembelajaran mendalam yang dilatih dengan berjuta-juta imej. Rangkaian neural menganalisis imej untuk mengenal pasti tepi dan maklumat konteks untuk mencipta topeng pemotongan yang tepat.\\n\\nTeknologi telah bertambah baik dengan ketara. Alat terdahulu memerlukan pemilihan manual. Model AI semasa mengendalikan kes-kes mencabar seperti rambut atau bulu secara automatik.\\n\\nSesetengah alat memproses di pelayan jauh. Yang lain, seperti ToolPic, menjalankan model AI terus dalam pelayar menggunakan WebAssembly, memastikan imej anda kekal peribadi."},{"heading":"Kes Penggunaan Biasa","text":"Fotografi produk e-dagang adalah antara aplikasi paling popular. Latar belakang putih atau lutsinar yang bersih adalah standard untuk pasaran dalam talian.\\n\\nPenghasilan kandungan media sosial sering memerlukan latar belakang lutsinar untuk melapisi imej dan mencipta kolaj.\\n\\nPereka profesional menggunakan pembuangan latar belakang sebagai titik permulaan untuk kerja gubahan dan bahan promosi."},{"heading":"Tips untuk Hasil Terbaik","text":"Kualiti hasil bergantung sebahagiannya pada imej input. Foto dengan kontras yang baik antara subjek dan latar belakang menghasilkan potongan paling bersih.\\n\\nElakkan imej di mana warna subjek hampir sama dengan warna latar belakang.\\n\\nUntuk fotografi produk, gunakan latar belakang berkontras semasa mengambil gambar. Latar putih atau kelabu ringkas berfungsi baik untuk kebanyakan produk."},{"heading":"Menggunakan ToolPic untuk Pembuangan Latar Belakang","text":"Buka alat Buang Latar Belakang di ToolPic dan muat naik imej anda. Model AI dimuatkan dalam pelayar pada penggunaan pertama, mengambil beberapa saat. Selepas itu, pemprosesan hampir serta-merta.\\n\\nAlat secara automatik mengesan subjek utama dan membuang latar belakang, menghasilkan PNG lutsinar.\\n\\nOleh kerana AI berjalan sepenuhnya dalam pelayar, imej anda tidak pernah dihantar ke mana-mana pelayan. Selamat digunakan dengan foto produk sulit dan kerja klien."}],"relatedToolIds":"image-bg-remove"},"reduce-video-file-size-for-email":{"title":"Cara Mengurangkan Saiz Fail Video untuk E-mel & Perkongsian","metaTitle":"Cara Mengurangkan Saiz Fail Video untuk E-mel & Perkongsian | Blog ToolPic","metaDescription":"Pelajari cara mengurangkan saiz fail video untuk lampiran e-mel dan perkongsian. Fahami resolusi, kadar bit, dan pilihan format untuk pemampatan optimum.","excerpt":"Teknik praktikal untuk mengecilkan fail video bagi lampiran e-mel, aplikasi pesanan, dan perkongsian media sosial.","content":[{"heading":"Mengapa Fail Video Sangat Besar","text":"Fail video besar kerana mengandungi urutan imej (bingkai) yang dimainkan pada 24 hingga 60 bingkai sesaat, bersama data audio. Satu minit video 1080p tidak dimampatkan pada 30 FPS memerlukan kira-kira 10GB storan.\\n\\nCodec video moden seperti H.264 dan H.265 menyimpan perbezaan antara bingkai berturut-turut, mencapai nisbah pemampatan 100:1 atau lebih baik.\\n\\nWalaupun dimampatkan, fail video harian masih besar untuk e-mel. Klip 1080p satu minit dari telefon pintar biasanya 100MB hingga 200MB, melebihi had lampiran 25MB kebanyakan penyedia e-mel."},{"heading":"Memahami Resolusi dan Kadar Bit","text":"Resolusi dan kadar bit adalah dua pengawal utama untuk saiz fail video. Mengurangkan resolusi separuh mengurangkan bilangan piksel sebanyak 75%.\\n\\nKadar bit adalah jumlah data sesaat video. Untuk perkongsian web, kadar bit 2-4 Mbps untuk kandungan 1080p menawarkan keseimbangan yang baik.\\n\\nUntuk lampiran e-mel, mengurangkan resolusi kepada 720p atau 480p biasanya paling berkesan."},{"heading":"Memilih Format Yang Tepat","text":"MP4 dengan pengekodan H.264 adalah format video paling serasi secara universal. Untuk perkongsian melalui e-mel atau pesanan, MP4 harus menjadi pilihan lalai anda.\\n\\nWebM menawarkan kecekapan pemampatan yang lebih baik tetapi keserasian kurang universal.\\n\\nH.265 (HEVC) memberikan pemampatan kira-kira 50% lebih baik daripada H.264 pada kualiti yang sama."},{"heading":"Pemampatan Langkah demi Langkah dengan ToolPic","text":"Buka alat Pemampat Video di ToolPic dan seret fail video ke kawasan muat naik. Alat menerima MP4, WebM, AVI, MOV, dan format biasa lain.\\n\\nPilih resolusi sasaran. Untuk e-mel, 720p biasanya titik manis. Untuk aplikasi pesanan, 480p selalunya mencukupi. Laraskan peluncur kualiti.\\n\\nKlik mampatkan dan tunggu pemprosesan selesai. Muat turun video yang dimampatkan dan sahkan ia dimainkan dengan betul. Semua pemprosesan berlaku secara tempatan dalam pelayar."}],"relatedToolIds":"video-compress"},"image-sizes-for-social-media-guide":{"title":"Panduan Saiz Imej Media Sosial 2026: Instagram, Facebook, Twitter","metaTitle":"Panduan Saiz Imej Media Sosial 2026 | Blog ToolPic","metaDescription":"Panduan lengkap saiz imej media sosial pada 2026. Dimensi yang disyorkan untuk Instagram, Facebook, Twitter/X, YouTube, LinkedIn, dan TikTok.","excerpt":"Rujukan lengkap untuk dimensi imej media sosial pada 2026, meliputi semua platform utama dan jenis penempatan.","content":[{"heading":"Mengapa Dimensi Imej Penting","text":"Platform media sosial memaparkan imej pada nisbah aspek dan resolusi tertentu. Apabila anda memuat naik imej yang tidak sepadan dimensi yang dijangka, platform akan memotongnya secara automatik, sering memotong bahagian penting.\\n\\nMenggunakan dimensi yang betul memastikan imej anda dipaparkan tepat seperti yang dikehendaki.\\n\\nSetiap platform mempunyai keperluan berbeza untuk penempatan berbeza."},{"heading":"Dimensi Instagram","text":"Siaran persegi Instagram hendaklah 1080 x 1080 piksel. Siaran potret berprestasi terbaik pada 1080 x 1350 piksel (nisbah 4:5).\\n\\nInstagram Stories dan Reels menggunakan format menegak 9:16 pada 1080 x 1920 piksel. Foto profil dipaparkan dalam bulatan pada 320 x 320 piksel.\\n\\nSiaran karusel boleh menggunakan sebarang saiz siaran standard, tetapi semua imej mesti mempunyai nisbah aspek yang sama."},{"heading":"Facebook, Twitter/X, dan YouTube","text":"Foto muka depan Facebook hendaklah 820 x 312 piksel di desktop tetapi berbeza di mudah alih (640 x 360). Foto profil 170 x 170 piksel. Imej dikongsi dalam suapan terbaik pada 1200 x 630 piksel.\\n\\nPengepala Twitter/X hendaklah 1500 x 500 piksel. Foto profil 400 x 400 piksel.\\n\\nLakaran kecil YouTube hendaklah tepat 1280 x 720 piksel. Sepanduk saluran 2560 x 1440 piksel, tetapi kawasan selamat ialah tengah 1546 x 423 piksel."},{"heading":"Cara Mengubah Saiz Imej dengan ToolPic","text":"Buka alat Potong & Ubah Saiz Imej di ToolPic dan muat naik imej anda. Alat menyertakan pratetap terbina untuk semua platform media sosial utama.\\n\\nPilih platform dan jenis penempatan dari menu pratetap. Alat secara automatik menetapkan nisbah aspek dan dimensi yang betul.\\n\\nMuat turun imej bersaiz sempurna sedia untuk dimuat naik. Alat mengekalkan kualiti imej asal dan memproses semuanya secara tempatan."}],"relatedToolIds":"image-crop"},"what-is-webp-format-and-why-use-it":{"title":"Apa itu Format WebP? Mengapa Anda Perlu Menggunakannya pada 2026","metaTitle":"Apa itu Format WebP? Mengapa Anda Perlu Menggunakannya pada 2026 | Blog ToolPic","metaDescription":"Pelajari apa itu format imej WebP, kelebihannya berbanding JPEG dan PNG, status sokongan pelayar, dan cara menukar imej anda ke WebP.","excerpt":"Semua yang anda perlu tahu tentang format imej WebP: kelebihan, sokongan pelayar, dan cara mula menggunakannya hari ini.","content":[{"heading":"Apa itu WebP","text":"WebP adalah format imej yang dibangunkan oleh Google dan dikeluarkan pada 2010 sebagai pengganti moden untuk JPEG, PNG, dan GIF. Ia menggunakan algoritma pemampatan canggih yang berasal dari codec video VP8 dan VP9.\\n\\nFormat ini menyokong kedua-dua mod pemampatan lossy dan lossless. Dalam mod lossy, WebP menghasilkan fail yang biasanya 25-35% lebih kecil daripada JPEG pada kualiti visual yang sama. Dalam mod lossless, fail WebP kira-kira 26% lebih kecil daripada PNG. Ia juga menyokong ketelusan dan animasi.\\n\\nWebP direka khusus untuk web, di mana saiz fail yang lebih kecil bermakna pemuatan halaman yang lebih pantas dan kos jalur lebar yang lebih rendah."},{"heading":"Kelebihan Berbanding JPEG dan PNG","text":"Kelebihan utama WebP ialah kecekapan pemampatan. Fail WebP pada kualiti 80% secara visual setara dengan JPEG pada 85-90% tetapi 30% lebih kecil. Untuk laman web dengan beratus-ratus imej, ini bermakna penjimatan jalur lebar yang ketara.\\n\\nBerbeza dengan JPEG, WebP menyokong ketelusan tanpa penalti saiz fail PNG. Imej produk dengan latar belakang lutsinar sebagai WebP biasanya 3-5 kali lebih kecil daripada PNG.\\n\\nWebP juga menyokong animasi sebagai alternatif kepada GIF dengan sokongan warna 24-bit penuh."},{"heading":"Sokongan Pelayar pada 2026","text":"Sehingga 2026, WebP disokong oleh semua pelayar utama termasuk Chrome, Firefox, Safari, Edge, dan Opera. Safari menambah sokongan WebP dalam versi 14 (2020). WebP kini berfungsi untuk lebih 97% pengguna web di seluruh dunia.\\n\\nSokongan pelayar mudah alih juga menyeluruh. Kedua-dua iOS Safari dan Android Chrome menyokong WebP sepenuhnya.\\n\\nKebimbangan keserasian yang tinggal kebanyakannya berkaitan perisian desktop lama. Menyimpan versi JPEG atau PNG sebagai sandaran adalah penyelesaian praktikal."},{"heading":"Cara Menukar Imej ke WebP","text":"Menukar imej sedia ada ke WebP mudah dengan Penukar Imej ToolPic. Muat naik sebarang imej JPEG, PNG, BMP, atau AVIF dan pilih WebP sebagai format output. Alat mengekalkan ketelusan dari sumber PNG.\\n\\nUntuk hasil terbaik, mulakan dengan imej sumber berkualiti tertinggi yang ada.\\n\\nSemasa memindahkan laman web ke WebP, gunakan elemen HTML picture atau CSS image-set untuk menyajikan WebP kepada pelayar yang disokong sambil menyediakan sandaran JPEG atau PNG. Kebanyakan penyedia CDN boleh mengautomasi proses ini."}],"relatedToolIds":"image-converter"},"how-to-convert-heic-to-jpg":{"title":"Cara Menukar HEIC ke JPG: Panduan Lengkap","metaTitle":"Cara Menukar HEIC ke JPG Percuma Dalam Talian | Blog ToolPic","metaDescription":"Ketahui cara menukar foto HEIC dari iPhone ke format JPG yang serasi secara universal. Panduan langkah demi langkah dengan petua untuk mengekalkan kualiti.","excerpt":"Panduan praktikal untuk menukar imej HEIC dari peranti Apple ke format JPG yang disokong di mana-mana.","content":[{"heading":"Apa itu Format HEIC dan Mengapa iPhone Menggunakannya","text":"HEIC bermaksud High Efficiency Image Container, format imej yang diterima pakai oleh Apple sejak iOS 11 pada 2017. Ia berasaskan kodek HEVC (H.265) dan direka untuk menyimpan foto berkualiti tinggi dengan saiz fail yang jauh lebih kecil berbanding JPEG. Secara purata, fail HEIC bersaiz 40% hingga 50% lebih kecil daripada JPEG pada kualiti visual yang setara.\\n\\nApple memilih HEIC kerana kecekapan penyimpanannya yang luar biasa. Memandangkan pengguna iPhone mengambil beribu-ribu gambar, penjimatan ruang ini amat ketara. HEIC juga menyokong ciri lanjutan seperti peta kedalaman, HDR, dan penyimpanan berbilang imej dalam satu fail (seperti Live Photos).\\n\\nNamun, masalah utama HEIC ialah keserasian. Banyak aplikasi Windows, penyunting imej dalam talian, platform media sosial, dan sistem CMS laman web tidak menyokong format ini secara asli. Inilah sebabnya penukaran ke JPG sering diperlukan."},{"heading":"Bila Anda Perlu Menukar HEIC ke JPG","text":"Situasi paling biasa ialah apabila anda ingin berkongsi foto iPhone dengan pengguna Android atau Windows. Penerima mungkin tidak dapat membuka fail HEIC tanpa perisian tambahan. Perkara yang sama berlaku apabila memuat naik imej ke laman web, kedai dalam talian, atau platform yang hanya menerima JPG dan PNG.\\n\\nUntuk tujuan profesional seperti fotografi produk e-dagang, portfolio dalam talian, atau bahan pemasaran, JPG kekal sebagai standard industri. Kebanyakan perkhidmatan cetak foto juga memerlukan fail dalam format JPG atau TIFF.\\n\\nPenukaran juga diperlukan apabila anda ingin menyunting foto dalam perisian yang belum menyokong HEIC. Walaupun Adobe Photoshop dan Lightroom sudah menyokongnya, banyak penyunting imej percuma dan dalam talian masih tidak serasi."},{"heading":"Petua Mengekalkan Kualiti Semasa Penukaran","text":"Kunci utama untuk mengekalkan kualiti ialah menggunakan tetapan kualiti JPG yang tepat. Tetapan 90% hingga 95% menghasilkan fail yang secara visual sama dengan asal, dengan peningkatan saiz fail yang sederhana berbanding tetapan lebih rendah.\\n\\nElakkan menukar berulang-alik antara format lossy. Setiap kali anda menyimpan imej dalam format lossy seperti JPG, sedikit data hilang. Jika anda bercadang menyunting foto lagi kemudian, simpan versi asal HEIC sebagai arkib.\\n\\nBeri perhatian juga kepada metadata EXIF. Penukar yang baik mengekalkan maklumat seperti tarikh pengambilan, lokasi GPS, tetapan kamera, dan orientasi imej. Kehilangan metadata ini boleh menjadi masalah untuk pengarkiban dan penyusunan foto."},{"heading":"Cara Menukar HEIC ke JPG dengan ToolPic","text":"Buka Penukar Imej di ToolPic dan seret fail HEIC anda ke kawasan muat naik. Anda boleh memilih berbilang fail sekaligus untuk pemprosesan kelompok yang cekap. Alat ini menyokong penukaran langsung dari HEIC ke pelbagai format termasuk JPG, PNG, dan WebP.\\n\\nPilih JPG sebagai format output dan tetapkan kualiti mengikut keperluan. Untuk kegunaan umum, kualiti 85% hingga 90% memberikan keseimbangan sempurna antara saiz fail dan kualiti visual. Pratonton masa nyata membantu anda mengesahkan hasilnya sebelum memuat turun.\\n\\nKlik butang tukar dan muat turun hasilnya secara individu atau sekaligus. Keseluruhan proses berlaku dalam pelayar anda, jadi foto peribadi anda tidak pernah dimuat naik ke mana-mana pelayan. Ini menjadikan ToolPic pilihan selamat untuk menukar foto sensitif atau peribadi."}],"relatedToolIds":"image-converter"},"ai-image-tools-vs-traditional":{"title":"Alat Imej AI vs Tradisional: Mana Lebih Baik?","metaTitle":"Alat Imej AI vs Penyuntingan Tradisional: Perbandingan Penuh | Blog ToolPic","metaDescription":"Bandingkan alat penyuntingan imej berasaskan AI dengan kaedah tradisional. Ketahui bila menggunakan AI dan bila pendekatan manual lebih baik.","excerpt":"Perbandingan mendalam antara alat penyuntingan imej berasaskan AI dan kaedah tradisional untuk membantu anda memilih pendekatan yang tepat.","content":[{"heading":"Evolusi Penyuntingan Imej","text":"Penyuntingan imej digital telah berevolusi secara dramatik dalam dua dekad yang lalu. Pada awalnya, setiap pelarasan memerlukan kemahiran teknikal tinggi dan berjam-jam kerja dalam perisian profesional seperti Adobe Photoshop. Malah tugas mudah seperti mengalih keluar latar belakang boleh mengambil masa 30 minit atau lebih untuk hasil yang kemas.\\n\\nKemunculan kecerdasan buatan telah mengubah landskap ini secara asas. Model pembelajaran mendalam yang dilatih pada berjuta-juta imej kini boleh melaksanakan dalam beberapa saat apa yang dahulu memerlukan bertahun-tahun pengalaman manual. Pengalihan latar belakang, peningkatan resolusi, pembetulan warna, dan pengalihan objek semuanya boleh dilakukan secara automatik.\\n\\nNamun, persoalannya tidak sesederhana AI sentiasa lebih baik. Setiap pendekatan mempunyai kekuatan dan kelemahannya, dan memahami perbezaan ini membantu anda memilih alat yang tepat untuk setiap tugas."},{"heading":"Kelebihan Alat Berasaskan AI","text":"Kelajuan adalah kelebihan terbesar alat AI. Pengalihan latar belakang yang dahulu memerlukan pemilihan manual piksel demi piksel kini selesai dalam 2-3 saat. Peningkatan resolusi yang memerlukan interpolasi manual kini menggunakan rangkaian neural untuk menjana butiran yang realistik.\\n\\nKonsistensi juga merupakan kelebihan besar. Alat AI memberikan hasil yang konsisten tanpa mengira tahap kemahiran pengguna. Seorang pemula mendapat hasil yang sama baiknya dengan seorang profesional apabila menggunakan alat pengalihan latar belakang AI.\\n\\nKebolehcapaian menjadi faktor utama lain. Alat AI berasaskan pelayar membolehkan sesiapa sahaja melakukan penyuntingan imej lanjutan tanpa membeli perisian mahal atau menghabiskan masa mempelajari antara muka yang rumit. Cukup muat naik imej dan biarkan AI melakukan kerjanya."},{"heading":"Bila Pendekatan Tradisional Lebih Baik","text":"Penyuntingan manual masih unggul untuk kerja kreatif yang memerlukan visi artistik tertentu. Kompositing kompleks, retouching potret tahap tinggi, dan manipulasi imej kreatif memerlukan kawalan yang AI pada masa ini tidak dapat berikan.\\n\\nUntuk output cetakan resolusi tinggi, kawalan manual ke atas pengurusan warna, profil ICC, dan tetapan ketajaman kekal penting. AI mungkin menghasilkan keputusan yang kelihatan baik di skrin tetapi kurang optimum untuk pengeluaran cetakan profesional.\\n\\nProjek penjenamaan dan reka bentuk yang memerlukan ketekalan piksel-sempurna merentas pelbagai aset juga lebih sesuai dengan pendekatan manual. Pereka bentuk memerlukan kawalan tepat ke atas setiap elemen, sesuatu yang sukar dicapai dengan alat automatik."},{"heading":"Pendekatan Terbaik: Gabungan Kedua-duanya","text":"Aliran kerja paling cekap menggabungkan kedua-dua pendekatan. Gunakan alat AI untuk tugas berulang dan memakan masa seperti pengalihan latar belakang secara kelompok, pemampatan imej, dan penukaran format. Ini menjimatkan berjam-jam yang boleh diperuntukkan untuk kerja kreatif.\\n\\nToolPic menawarkan alat pengalihan latar belakang berasaskan AI yang berjalan terus dalam pelayar. Model AI memproses imej secara setempat tanpa memuat naik ke pelayan, menggabungkan kelajuan AI dengan privasi penuh. Hasilnya boleh terus digunakan atau disunting lagi dalam perisian reka bentuk kegemaran anda.\\n\\nUntuk jurugambar dan pereka bentuk profesional, alat AI berfungsi sebagai titik permulaan yang sangat baik. Mulakan dengan pengalihan latar belakang AI, kemudian perhalusi butirannya secara manual jika perlu. Pendekatan hibrid ini menghasilkan kualiti tertinggi dalam masa terpantas."}],"relatedToolIds":"image-bg-remove"},"how-to-optimize-images-for-website-speed":{"title":"Cara Mengoptimumkan Imej untuk Kelajuan Laman Web","metaTitle":"Cara Mengoptimumkan Imej untuk Kelajuan Laman Web | Blog ToolPic","metaDescription":"Pelajari teknik pengoptimuman imej untuk mempercepatkan laman web anda. Panduan lengkap tentang pemampatan, format, saiz, dan lazy loading.","excerpt":"Panduan lengkap untuk mengoptimumkan imej supaya laman web anda memuat lebih pantas, meningkatkan SEO, dan memberikan pengalaman pengguna yang lebih baik.","content":[{"heading":"Kesan Imej terhadap Kelajuan Laman Web","text":"Imej biasanya menyumbang 50% hingga 75% daripada jumlah berat halaman web. Halaman dengan sepuluh imej yang tidak dioptimumkan boleh memerlukan 5MB atau lebih untuk dimuat, menyebabkan pelawat menunggu dan berkemungkinan meninggalkan laman sebelum kandungan muncul.\\n\\nGoogle menggunakan Core Web Vitals sebagai faktor kedudukan, dan Largest Contentful Paint (LCP) sangat dipengaruhi oleh imej. LCP mengukur masa yang diperlukan untuk elemen kandungan terbesar muncul di skrin, yang selalunya adalah imej hero atau sepanduk. Jika LCP melebihi 2.5 saat, kedudukan carian anda boleh terjejas.\\n\\nPengguna mudah alih sangat terkesan kerana sambungan selular lebih perlahan dan data sering terhad. Mengoptimumkan imej bukan sahaja mempercepatkan laman web tetapi juga menjimatkan kuota data pelawat mudah alih anda."},{"heading":"Memilih Format dan Pemampatan yang Tepat","text":"Langkah pertama ialah memilih format imej yang betul. Gunakan WebP sebagai format lalai untuk web kerana ia menawarkan pemampatan terbaik. Untuk foto, WebP lossy pada kualiti 75-85% menghasilkan fail 30% lebih kecil daripada JPEG tanpa kehilangan kualiti yang ketara. Untuk grafik dengan ketelusan, WebP lossless jauh lebih kecil daripada PNG.\\n\\nJika keserasian pelayar lama menjadi kebimbangan, gunakan elemen HTML picture untuk menyajikan WebP dengan sandaran JPEG. Pada 2026, lebih daripada 97% pelayar menyokong WebP, jadi ini semakin jarang menjadi masalah.\\n\\nPemampatan agresif lebih selamat daripada yang anda sangka. Kebanyakan pelawat tidak dapat membezakan antara JPEG kualiti 80% dan 100% pada skrin mereka. Mulakan dengan kualiti 80% dan turunkan hanya jika hasilnya tidak memuaskan secara visual."},{"heading":"Saiz Imej dan Teknik Responsif","text":"Jangan sesekali menyajikan imej yang lebih besar daripada yang dipaparkan. Menghantar imej 4000px ke bekas 800px bermaksud 80% data terbuang sia-sia. Cipta pelbagai versi imej untuk titik putus berbeza menggunakan atribut srcset.\\n\\nLaksanakan lazy loading dengan menambah loading=\\"lazy\\" pada tag img. Ini menangguhkan pemuatan imej yang belum kelihatan dalam viewport, mengurangkan masa muat awal dengan ketara. Imej di atas lipatan (yang terus kelihatan) harus tetap dimuat serta-merta.\\n\\nGunakan atribut width dan height pada tag img untuk mengelakkan anjakan susun atur. Tanpa dimensi ini, pelayar tidak tahu berapa banyak ruang yang perlu disediakan untuk imej, menyebabkan kandungan bergerak apabila imej dimuat. Ini memberi kesan negatif pada skor Cumulative Layout Shift (CLS)."},{"heading":"Mengoptimumkan Imej dengan ToolPic","text":"ToolPic menyediakan dua alat utama untuk pengoptimuman imej laman web. Pemampat Imej membolehkan anda mengurangkan saiz fail dengan tetapan kualiti yang boleh dilaras. Muat naik banyak imej sekaligus, tetapkan kualiti sasaran, dan muat turun hasilnya dalam beberapa saat.\\n\\nPenukar Imej membantu anda beralih ke format yang lebih cekap seperti WebP. Cukup muat naik imej JPG atau PNG, pilih WebP sebagai format output, dan alat akan menghasilkan versi yang lebih kecil dengan kualiti visual yang setanding.\\n\\nKedua-dua alat memproses imej sepenuhnya dalam pelayar, menjadikannya sesuai untuk mengoptimumkan imej laman web pelanggan tanpa risiko kebocoran data. Pemprosesan kelompok membolehkan anda mengoptimumkan keseluruhan galeri atau katalog produk sekaligus, menjimatkan masa yang ketara berbanding pengoptimuman satu per satu."}],"relatedToolIds":"image-compressor,image-converter"}}}}');
